export const ShippingListMethodsForCheckoutDocument = gql`
  fragment AddressFragment on Address {
    firstName
    lastName
    companyName
    streetAddress1
    streetAddress2
    city
    postalCode
    countryArea
    country {
      code
    }
    phone
  }
  subscription ShippingListMethodsForCheckout {
    event {
      ... on ShippingListMethodsForCheckout {
        checkout {
          id
          channel {
            id
            slug
          }
          totalPrice {
            gross {
              amount
              currency
            }
          }
          shippingAddress {
            ...AddressFragment
          }
          billingAddress {
            ...AddressFragment
          }
          lines {
            id
            quantity
            variant {
              id
              sku
              name
              weight {
                value
                unit
              }
              product {
                id
                name
                weight {
                  value
                  unit
                }
              }
            }
            totalPrice {
              gross {
                amount
                currency
              }
            }
          }
        }
      }
    }
  }
`;

